WITH module_ref AS (
  SELECT m.id AS module_id FROM course_modules m
  JOIN courses c ON m.course_id = c.id
  JOIN organizations o ON c.org_id = o.id
  WHERE o.slug = 'default-org' AND c.slug = 'cooking-basics' AND m.slug = 'main'
), inserted_page AS (
  INSERT INTO lesson_pages (module_id, sort_order, legacy_page_id, page_type, quiz_mode, content)
  SELECT module_id, 3, 3, 'cover', NULL, '{"author":"รวบรวมโดย: อ. กฤดิทร สุขกมล","course":"รายวิชา: การประกอบอาหารเบื้องต้น","details":"หมวดวิชาคหกรรมศาสตร์ แผนกอาหารและโภชนาการ\nเอกสารประกอบการสอนฉบับมาตรฐาน\nภาคเรียนที่ 1 ปีการศึกษา 2569","image":"[https://images.unsplash.com/photo-1600565193348-f74bd3c7ccdf?auto=format&fit=crop&w=1600&q=80&fm=webp](https://images.unsplash.com/photo-1600565193348-f74bd3c7ccdf?auto=format&fit=crop&w=1600&q=80&fm=webp)"}'::jsonb FROM module_ref
  ON CONFLICT (module_id, sort_order) DO UPDATE SET legacy_page_id = EXCLUDED.legacy_page_id, page_type = EXCLUDED.page_type, quiz_mode = EXCLUDED.quiz_mode, content = EXCLUDED.content
  RETURNING id
)
INSERT INTO page_translations (page_id, locale, title, subtitle, body)
  SELECT id, 'th', 'ความรู้เบื้องต้นเกี่ยวกับการประกอบอาหาร', 'เอกสารประกอบการเรียนเชิงวิชาการ / E-Learning Module (หลักสูตร 4 ชั่วโมง)', '{}'::jsonb FROM inserted_page
  ON CONFLICT (page_id, locale) DO UPDATE SET title = EXCLUDED.title, subtitle = EXCLUDED.subtitle;

-- Page 4: article
WITH module_ref AS (
  SELECT m.id AS module_id FROM course_modules m
  JOIN courses c ON m.course_id = c.id
  JOIN organizations o ON c.org_id = o.id
  WHERE o.slug = 'default-org' AND c.slug = 'cooking-basics' AND m.slug = 'main'
), inserted_page AS (
  INSERT INTO lesson_pages (module_id, sort_order, legacy_page_id, page_type, quiz_mode, content)
  SELECT module_id, 4, 4, 'article', NULL, '{"image":"[https://images.unsplash.com/photo-1495521821757-a1efb6729352?auto=format&fit=crop&w=800&q=80&fm=webp](https://images.unsplash.com/photo-1495521821757-a1efb6729352?auto=format&fit=crop&w=800&q=80&fm=webp)","sections":[{"subtitle":"การประกอบอาหารคืออะไร?","content":"การประกอบอาหาร หมายถึงกระบวนการนำวัตถุดิบและอาหารดิบมาทำให้สุกด้วยความร้อน เพื่อทำให้อาหารมีคุณสมบัติที่เหมาะสมและมีคุณค่าแก่การบริโภค กระบวนการนี้ไม่ได้มีแค่การตั้งไฟ แต่ครอบคลุมตั้งแต่กระบวนการคัดเลือกวัตถุดิบที่สดใหม่ การล้างทำความสะอาด การหั่นเตรียม (Mise en place) การปรุงด้วยเทคนิคความร้อนที่เหมาะสม การจัดเสิร์ฟที่สวยงาม และการเก็บรักษาอย่างถูกวิธี"},{"subtitle":"องค์ประกอบแห่งความสำเร็จ","content":"การประกอบอาหารที่ดีจะต้องคำนึงถึง \"ความสะอาดและถูกสุขลักษณะ\" เป็นหัวใจสำคัญสูงสุด องค์ประกอบที่สำคัญเริ่มต้นตั้งแต่ตัว \"ผู้ประกอบอาหาร\" ที่ต้องมีสุขอนามัยที่ดี อุปกรณ์ที่ใช้ต้องสะอาด ตำรับอาหารต้องได้มาตรฐาน เครื่องปรุงต้องช่วยส่งเสริมคุณค่า รสชาติ กลิ่น และเนื้อสัมผัสที่ดี รวมไปถึงศิลปะและทักษะในการประกอบอาหาร รูปแบบการเสิร์ฟ ภาชนะบรรจุ และการคำนวณช่วงเวลาในการเสิร์ฟที่แม่นยำ"},{"subtitle":"ผลลัพธ์ที่ได้จากการประกอบอาหาร","content":"อาหารที่ผ่านการปรุงสุกอย่างถูกต้องตามหลักวิชาการ เมื่อรับประทานเข้าไปแล้วจะมีประโยชน์สูงสุดต่อร่างกาย ทำให้ร่างกายเจริญเติบโต ซ่อมแซมส่วนที่สึกหรอ ส่งผลดีต่อทั้งสุขภาพกาย (ปราศจากโรคภัย) และสุขภาพใจ (ความสุขจากการได้รับประทานอาหารที่รสชาติดี)"}]}'::jsonb FROM module_ref
  ON CONFLICT (module_id, sort_order) DO UPDATE SET legacy_page_id = EXCLUDED.legacy_page_id, page_type = EXCLUDED.page_type, quiz_mode = EXCLUDED.quiz_mode, content = EXCLUDED.content
  RETURNING id
)
INSERT INTO page_translations (page_id, locale, title, subtitle, body)
  SELECT id, 'th', 'ความหมายของการประกอบอาหาร', '', '{}'::jsonb FROM inserted_page
  ON CONFLICT (page_id, locale) DO UPDATE SET title = EXCLUDED.title, subtitle = EXCLUDED.subtitle;

-- Page 5: cards-grid
WITH module_ref AS (
  SELECT m.id AS module_id FROM course_modules m
  JOIN courses c ON m.course_id = c.id
  JOIN organizations o ON c.org_id = o.id
  WHERE o.slug = 'default-org' AND c.slug = 'cooking-basics' AND m.slug = 'main'
), inserted_page AS (
  INSERT INTO lesson_pages (module_id, sort_order, legacy_page_id, page_type, quiz_mode, content)
  SELECT module_id, 5, 5, 'cards_grid', NULL, '{"items":[{"icon":"ShieldCheck","title":"1. ทำให้อาหารสุก สะอาด ปราศจากเชื้อโรค","desc":"อาหารที่สุกด้วยการปรุงผ่านความร้อนสูงและเป็นเวลานานพอสมควร ทำให้แน่ใจได้ว่าแบคทีเรีย เชื้อโรค และพยาธิที่แฝงมากับวัตถุดิบถูกทำลายไปแล้ว จึงจะสะอาดเพียงพอสำหรับการรับประทานอย่างปลอดภัย ถูกสุขลักษณะ"},{"icon":"HeartPulse","title":"2. สงวนคุณค่าทางโภชนาการ","desc":"แม้ความร้อนจะทำลายสารอาหารบางชนิด โดยเฉพาะ \"วิตามินที่ละลายน้ำได้ เช่น วิตามิน B และ C\" แต่การเลือกเทคนิคที่ถูกต้อง (เช่น การนึ่งแทนการต้มน้ำทิ้ง) จะช่วยสงวนคุณค่าทางอาหารไว้ให้ร่างกายดูดซึมได้มากที่สุด"},{"icon":"Sparkles","title":"3. ทำให้อาหารย่อยง่ายขึ้น","desc":"ความร้อนทำให้โปรตีนในเนื้อสัตว์คลายตัวและแป้งสุกตัว เครื่องปรุงรสที่ใช้มีผลโดยตรงต่อความนุ่มของเนื้อสัมผัส ทำให้กระเพาะอาหารและลำไส้ของเราทำงานเบาลงและย่อยได้ง่ายขึ้น"},{"icon":"Flame","title":"4. รสชาติและกลิ่นดีขึ้น (เกิดปฏิกิริยาเคมี)","desc":"ความร้อนก่อให้เกิดปฏิกิริยา Maillard (การเกิดสีน้ำตาลและกลิ่นหอม) ทำให้อาหารมีการเปลี่ยนแปลงทางเคมี ส่งผลให้รสชาติ กลิ่น และสีสันเปลี่ยนไปในทางที่ดีขึ้น กระตุ้นความอยากอาหาร"},{"icon":"Timer","title":"5. ป้องกันการเน่าเสีย เก็บได้นานขึ้น","desc":"เอนไซม์และแบคทีเรียคือตัวการสำคัญที่ทำให้อาหารเน่าเสีย ความร้อนจากการประกอบอาหารจะช่วยยับยั้งและทำลายการทำงานของพวกมัน ช่วยยืดอายุการเก็บรักษาอาหารได้นานขึ้น"}]}'::jsonb FROM module_ref
  ON CONFLICT (module_id, sort_order) DO UPDATE SET legacy_page_id = EXCLUDED.legacy_page_id, page_type = EXCLUDED.page_type, quiz_mode = EXCLUDED.quiz_mode, content = EXCLUDED.content
  RETURNING id
)
