-- Page 9: methods
WITH module_ref AS (
  SELECT m.id AS module_id FROM course_modules m
  JOIN courses c ON m.course_id = c.id
  JOIN organizations o ON c.org_id = o.id
  WHERE o.slug = 'default-org' AND c.slug = 'cooking-basics' AND m.slug = 'main'
), inserted_page AS (
  INSERT INTO lesson_pages (module_id, sort_order, legacy_page_id, page_type, quiz_mode, content)
  SELECT module_id, 9, 9, 'methods', NULL, '{"items":[{"name":"1. การปิ้ง (Grill)","desc":"การนำอาหารวางลงบนตะแกรงเหล็กเหนือเตาถ่านที่มีความร้อนไม่มาก ปิ้งกลับไปมาในเวลาสั้นๆ ใช้ได้ทั้งอาหารสดและแห้ง ช่วยให้อาหารมีกลิ่นควันอ่อนๆ","image":"[https://images.unsplash.com/photo-1555939594-58d7cb561ad1?auto=format&fit=crop&w=600&q=80&fm=webp](https://images.unsplash.com/photo-1555939594-58d7cb561ad1?auto=format&fit=crop&w=600&q=80&fm=webp)"},{"name":"2. การย่าง (Roast / BBQ)","desc":"คล้ายการปิ้งแต่ใช้เวลานานกว่าและชิ้นเนื้อใหญ่กว่า เพื่อให้อาหารสุกระอุทั่วถึงกัน มักทาน้ำมันหรือห่อใบตองเพื่อกันไหม้และเพิ่มกลิ่นหอม ย่างข้างละ 2 นาทีแล้วพลิก","image":"[https://images.unsplash.com/photo-1529692236671-f1f6cf9683ba?auto=format&fit=crop&w=600&q=80&fm=webp](https://images.unsplash.com/photo-1529692236671-f1f6cf9683ba?auto=format&fit=crop&w=600&q=80&fm=webp)"},{"name":"3. การเผา (Burn)","desc":"ทำให้อาหารสุกโดยใช้ไฟแรง วางของที่จะเผาลงบนไฟโดยตรงหรือสัมผัสความร้อนใกล้ชิด พลิกกลับไปมาให้สุกทั้งด้านนอกและด้านใน","image":"[https://images.unsplash.com/photo-1529193591184-b1d58069ecdd?auto=format&fit=crop&w=600&q=80&fm=webp](https://images.unsplash.com/photo-1529193591184-b1d58069ecdd?auto=format&fit=crop&w=600&q=80&fm=webp)"},{"name":"4. การอบ (Bake / Roast in Oven)","desc":"ใช้อากาศร้อนหมุนเวียนจากเตาอบ (เช่น อุณหภูมิ 190 องศาฯ สำหรับไก่อบ ใช้เวลา 20-30 นาที) ต้องอุ่นเตาอบให้ร้อนก่อนเสมอ (Pre-heat 15 นาที)","image":"[https://images.unsplash.com/photo-1509440159596-0249088772ff?auto=format&fit=crop&w=600&q=80&fm=webp](https://images.unsplash.com/photo-1509440159596-0249088772ff?auto=format&fit=crop&w=600&q=80&fm=webp)"}],"pros":"ข้อดี: เป็นวิธีการประกอบอาหารที่ช่วย \"สงวนคุณค่าทางโภชนาการ\" ไว้ได้มาก ผิวอาหารจะหอม มีสีเข้มสวยงาม (Maillard reaction) และดูน่ารับประทาน","cons":"ข้อเสีย: หากใช้เวลาในการทำนานเกินไป จะทำให้อาหารสูญเสียน้ำ แห้งกระด้างเกินไป ดูไม่น่ารับประทานและเสียรสชาติ"}'::jsonb FROM module_ref
  ON CONFLICT (module_id, sort_order) DO UPDATE SET legacy_page_id = EXCLUDED.legacy_page_id, page_type = EXCLUDED.page_type, quiz_mode = EXCLUDED.quiz_mode, content = EXCLUDED.content
  RETURNING id
)
