-- Page 10: methods
WITH module_ref AS (
  SELECT m.id AS module_id FROM course_modules m
  JOIN courses c ON m.course_id = c.id
  JOIN organizations o ON c.org_id = o.id
  WHERE o.slug = 'default-org' AND c.slug = 'cooking-basics' AND m.slug = 'main'
), inserted_page AS (
  INSERT INTO lesson_pages (module_id, sort_order, legacy_page_id, page_type, quiz_mode, content)
  SELECT module_id, 10, 10, 'methods', NULL, '{"items":[{"name":"5. การต้ม (Boil)","desc":"ใส่อาหารในน้ำเดือด (100°C) จนสุก เหมาะสำหรับเคี่ยวเนื้อสัตว์ให้เปื่อย (ข้อเสีย: วิตามินที่ละลายน้ำได้ เช่น B และ C มักละลายทิ้งไปกับน้ำต้ม)","image":"[https://images.unsplash.com/photo-1547592180-85f173990554?auto=format&fit=crop&w=600&q=80&fm=webp](https://images.unsplash.com/photo-1547592180-85f173990554?auto=format&fit=crop&w=600&q=80&fm=webp)"},{"name":"6. การลวก (Blanch)","desc":"ทำให้อาหารกึ่งสุกกึ่งดิบในน้ำเดือดจัดระยะสั้นๆ แล้ว \"แช่น้ำเย็นทันที\" เพื่อหยุดความร้อน ช่วยสงวนวิตามินและสีสันของผัก (ไม่เหมาะกับผักเนื้อแข็ง)","image":"[https://images.unsplash.com/photo-1506368249639-73a05d6f6488?auto=format&fit=crop&w=600&q=80&fm=webp](https://images.unsplash.com/photo-1506368249639-73a05d6f6488?auto=format&fit=crop&w=600&q=80&fm=webp)"},{"name":"7. การนึ่ง (Steam)","desc":"ใช้ไอน้ำจากน้ำเดือดในหม้อนึ่ง/ลังถึง วางอาหารชั้นบนปิดฝาให้สนิท สารอาหารไม่สัมผัสน้ำโดยตรง จึง \"สงวนคุณค่าทางอาหารได้ดีกว่าการต้ม\"","image":"[https://images.unsplash.com/photo-1563245372-f21724e3856d?auto=format&fit=crop&w=600&q=80&fm=webp](https://images.unsplash.com/photo-1563245372-f21724e3856d?auto=format&fit=crop&w=600&q=80&fm=webp)"},{"name":"8. การตุ๋น (Simmer / Double Boiler)","desc":"มักใช้หม้อ 2 ชั้นซ้อนกัน ใช้ไฟอ่อน อาหารจะสุกนุ่มละลายในปาก ปราศจากเชื้อโรค เหมาะสำหรับเด็กทารก ผู้ป่วย ผู้สูงอายุ (ข้อเสีย: ใช้เวลาปรุงนาน)","image":"[https://images.unsplash.com/photo-1604908176997-125f25cc6f3d?auto=format&fit=crop&w=600&q=80&fm=webp](https://images.unsplash.com/photo-1604908176997-125f25cc6f3d?auto=format&fit=crop&w=600&q=80&fm=webp)"}]}'::jsonb FROM module_ref
  ON CONFLICT (module_id, sort_order) DO UPDATE SET legacy_page_id = EXCLUDED.legacy_page_id, page_type = EXCLUDED.page_type, quiz_mode = EXCLUDED.quiz_mode, content = EXCLUDED.content
  RETURNING id
)
