  SELECT module_id, 11, 11, 'methods', NULL, '{"items":[{"name":"9. การผัด (Stir-Frying)","desc":"ใช้น้ำมันเล็กน้อย ใช้ไฟแรง นำเนื้อหรือผักลงกระทะ ใช้ตะหลิวคนกลับไปมาในระยะเวลาสั้นๆ ปริมาณไขมันน้อยกว่าทอด (ข้อเสีย: ถ้านานไปสีจะไม่สวย)","image":"[https://images.unsplash.com/photo-1512058564366-18510be2db19?auto=format&fit=crop&w=600&q=80&fm=webp](https://images.unsplash.com/photo-1512058564366-18510be2db19?auto=format&fit=crop&w=600&q=80&fm=webp)"},{"name":"10. การทอด (Frying)","desc":"นำอาหารลงไปทอดในน้ำมันร้อนๆ ปริมาณมาก ควรทอดด้านหนึ่งให้สุกก่อนค่อยกลับด้าน อาหารมีกลิ่นหอม สีสวย กรอบ (ข้อเสีย: อมไขมันสูง)","image":"[https://images.unsplash.com/photo-1569691899455-88464f6d3ab1?auto=format&fit=crop&w=600&q=80&fm=webp](https://images.unsplash.com/photo-1569691899455-88464f6d3ab1?auto=format&fit=crop&w=600&q=80&fm=webp)"},{"name":"เพิ่มเติม 1: การเจียว","desc":"ทำอาหารให้สุกในน้ำมันโดย \"ใช้ไฟอ่อน\" วัตถุดิบมักถูกซอยละเอียด ใส่ตอนน้ำมันยังไม่ร้อนจัด เจียวจนเหลืองกรอบ เช่น กระเทียมเจียว","image":"[https://images.unsplash.com/photo-1628294895950-9805252327bc?auto=format&fit=crop&w=600&q=80&fm=webp](https://images.unsplash.com/photo-1628294895950-9805252327bc?auto=format&fit=crop&w=600&q=80&fm=webp)"},{"name":"เพิ่มเติม 2: การคั่ว และ การรวน","desc":"คั่ว: \"ไม่ใช้น้ำมัน\" ใส่ภาชนะแห้ง ใช้ไฟอ่อนคนตลอดจนหอมกรอบ | รวน: คล้ายคั่วแต่ \"ใส่น้ำมันเล็กน้อย\" ปรุงรสเค็ม เพื่อถนอมเนื้อสัตว์","image":"[https://images.unsplash.com/photo-1558222218-b7b54eede3f3?auto=format&fit=crop&w=600&q=80&fm=webp](https://images.unsplash.com/photo-1558222218-b7b54eede3f3?auto=format&fit=crop&w=600&q=80&fm=webp)"}]}'::jsonb FROM module_ref
  ON CONFLICT (module_id, sort_order) DO UPDATE SET legacy_page_id = EXCLUDED.legacy_page_id, page_type = EXCLUDED.page_type, quiz_mode = EXCLUDED.quiz_mode, content = EXCLUDED.content
  RETURNING id
)
